input.command:
cat /etc/shadow | awk -F: '{
    username=$1
    hash=$2

    # Skip empty passwords and disabled accounts
    if (hash == "" || hash == "*" || hash == "!" || hash == "!!") {
        type="DISABLED/NO_PASSWORD"
    }
    # Check hash algorithm by prefix
    else if (hash ~ /^\$1\$/) {
        type="MD5 (crypt)"
    }
    else if (hash ~ /^\$2[aby]\$/) {
        type="Bcrypt"
    }
    else if (hash ~ /^\$5\$/) {
        type="SHA-256"
    }
    else if (hash ~ /^\$6\$/) {
        type="SHA-512"
    }
    else if (hash ~ /^\$7\$/) {
        type="Scrypt"
    }
    else if (hash ~ /^\$argon2/) {
        type="Argon2"
    }
    else {
        type="UNKNOWN/LEGACY"
    }

    printf "%-15s | %s\n", username, type
}' | column -t

